test_y() ->
    lists:foreach(fun run_y_test/1, y_tests()),
    ok.

test_n() ->
    lists:foreach(fun run_n_test/1, n_tests()),
    ok.

test_i() ->
    lists:foreach(fun run_i_test/1, i_tests()),
    ok.

test_t() ->
    lists:foreach(fun run_i_test/1, t_tests()),
    ok.

test_y_roundtrip() ->
    lists:foreach(fun run_y_roundtrip/1, y_tests()),
    ok.

test_i_roundtrip() ->
    lists:foreach(fun run_i_roundtrip/1, i_tests()),
    ok.

run_y_test({_Name, B64, Expected0}) ->
    Expected = resolve(Expected0),
    Expected = json:decode(base64:decode(B64)).

run_n_test({Name, B64, _}) ->
    Bin = base64:decode(B64),
    try json:decode(Bin) of
        Result -> error({should_have_failed, Name, Result})
    catch
        error:_ -> ok
    end.

run_i_test({Name, B64, Expected0}) ->
    case resolve(Expected0) of
        {ok, Expected} ->
            Expected = json:decode(base64:decode(B64));
        {error, _} ->
            Bin = base64:decode(B64),
            try json:decode(Bin) of
                Result -> error({should_have_failed, Name, Result})
            catch
                error:_ -> ok
            end
    end.

run_y_roundtrip({_Name, B64, Expected0}) ->
    Expected = resolve(Expected0),
    Decoded = json:decode(base64:decode(B64)),
    Decoded = json:decode(iolist_to_binary(json:encode(Expected))).

run_i_roundtrip({_Name, B64, Expected0}) ->
    case resolve(Expected0) of
        {ok, Expected} ->
            Decoded = json:decode(base64:decode(B64)),
            Decoded = json:decode(iolist_to_binary(json:encode(Expected)));
        {error, _} ->
            ok
    end.

resolve({external_term, Enc}) ->
    binary_to_term(base64:decode(Enc));
resolve(Term) ->
    Term.

to_bin(IoData) -> iolist_to_binary(IoData).

test_decode_basic() ->
    0 = json:decode(<<"0">>),
    1 = json:decode(<<"1">>),
    42 = json:decode(<<"42">>),
    123456789 = json:decode(<<"123456789">>),
    -1 = json:decode(<<"-1">>),
    -42 = json:decode(<<"-42">>),

    ?ASSERT_EQUALS(0.0, json:decode(<<"0.0">>)),
    ?ASSERT_EQUALS(3.14, json:decode(<<"3.14">>)),
    ?ASSERT_EQUALS(-2.5, json:decode(<<"-2.5">>)),
    ?ASSERT_EQUALS(0.1, json:decode(<<"0.1">>)),
    ?ASSERT_EQUALS(100.0, json:decode(<<"100.0">>)),

    ?ASSERT_EQUALS(1.0e5, json:decode(<<"1e5">>)),
    ?ASSERT_EQUALS(1.0e5, json:decode(<<"1E5">>)),
    ?ASSERT_EQUALS(1.0e5, json:decode(<<"1e+5">>)),
    ?ASSERT_EQUALS(1.0e-3, json:decode(<<"1e-3">>)),
    ?ASSERT_EQUALS(1.5e3, json:decode(<<"1.5e3">>)),
    ?ASSERT_EQUALS(1.5e-2, json:decode(<<"1.5e-2">>)),
    ?ASSERT_EQUALS(-1.0e5, json:decode(<<"-1e5">>)),
    ?ASSERT_EQUALS(-2.5e10, json:decode(<<"-2.5e10">>)),
    ?ASSERT_EQUALS(0.0e0, json:decode(<<"0e0">>)),
    ?ASSERT_EQUALS(0.0e0, json:decode(<<"0E0">>)),

    0 = json:decode(<<"-0">>),
    ?ASSERT_EQUALS(-0.0, json:decode(<<"-0.0">>)),

    true = json:decode(<<"true">>),
    false = json:decode(<<"false">>),
    null = json:decode(<<"null">>),
    ok.

test_decode_strings() ->
    <<>> = json:decode(<<"\"\"">>),
    <<"hello">> = json:decode(<<"\"hello\"">>),
    <<"hello world">> = json:decode(<<"\"hello world\"">>),

    <<"\"">> = json:decode(<<"\"\\\"\"">>),
    <<"\\">> = json:decode(<<"\"\\\\\"">>),
    <<"/">> = json:decode(<<"\"\\/\"">>),
    <<"\b">> = json:decode(<<"\"\\b\"">>),
    <<"\f">> = json:decode(<<"\"\\f\"">>),
    <<"\n">> = json:decode(<<"\"\\n\"">>),
    <<"\r">> = json:decode(<<"\"\\r\"">>),
    <<"\t">> = json:decode(<<"\"\\t\"">>),

    <<"hello\nworld">> = json:decode(<<"\"hello\\nworld\"">>),
    <<"\t\n\r">> = json:decode(<<"\"\\t\\n\\r\"">>),

    <<"A">> = json:decode(<<"\"\\u0041\"">>),
    <<16#C3, 16#A9>> = json:decode(<<"\"\\u00e9\"">>),
    <<16#C3, 16#A9>> = json:decode(<<"\"\\u00E9\"">>),
    <<0>> = json:decode(<<"\"\\u0000\"">>),
    <<16#E4, 16#B8, 16#96>> = json:decode(<<"\"\\u4e16\"">>),

    <<16#F0, 16#9F, 16#98, 16#80>> = json:decode(<<"\"\\uD83D\\uDE00\"">>),

    <<"A\nB">> = json:decode(<<"\"\\u0041\\nB\"">>),
    ok.

test_decode_containers() ->
    [] = json:decode(<<"[]">>),
    [1] = json:decode(<<"[1]">>),
    [1, 2, 3] = json:decode(<<"[1,2,3]">>),
    [1, <<"two">>, true, null] = json:decode(<<"[1, \"two\", true, null]">>),
    [[]] = json:decode(<<"[[]]">>),
    [[1, 2], [3, 4]] = json:decode(<<"[[1,2],[3,4]]">>),
    [[[1]]] = json:decode(<<"[[[1]]]">>),

    ?ASSERT_MATCH(#{}, json:decode(<<"{}">>)),
    ?ASSERT_MATCH(#{<<"a">> => 1}, json:decode(<<"{\"a\": 1}">>)),
    ?ASSERT_MATCH(#{<<"a">> => 1, <<"b">> => 2}, json:decode(<<"{\"a\": 1, \"b\": 2}">>)),
    ?ASSERT_MATCH(#{<<"a">> => #{<<"b">> => 1}}, json:decode(<<"{\"a\": {\"b\": 1}}">>)),
    ?ASSERT_MATCH(#{<<"items">> => [1, 2, 3]}, json:decode(<<"{\"items\": [1, 2, 3]}">>)),
    ok.

test_decode_whitespace() ->
    42 = json:decode(<<"  42  ">>),
    42 = json:decode(<<"\t42\n">>),
    42 = json:decode(<<"\r\n42\r\n">>),
    [1, 2] = json:decode(<<"[ 1 , 2 ]">>),
    ?ASSERT_MATCH(#{<<"a">> => 1}, json:decode(<<"{ \"a\" : 1 }">>)),
    [1] = json:decode(<<" \t\r\n[ \t\r\n1 \t\r\n] \t\r\n">>),
    ok.

test_decode_errors() ->
    ?ASSERT_ERROR(json:decode(<<>>)),
    ?ASSERT_ERROR(json:decode(<<"  ">>)),
    ?ASSERT_ERROR(json:decode(<<"\"unterminated">>)),
    ?ASSERT_ERROR(json:decode(<<"[1,">>)),
    ?ASSERT_ERROR(json:decode(<<"{\"a\"">>)),
    ?ASSERT_ERROR(json:decode(<<"{\"a\":">>)),
    ?ASSERT_ERROR(json:decode(<<"[">>)),
    ?ASSERT_ERROR(json:decode(<<"{">>)),

    ?ASSERT_ERROR(json:decode(<<"x">>)),
    ?ASSERT_ERROR(json:decode(<<",">>)),
    ?ASSERT_ERROR(json:decode(<<"42x">>)),
    ?ASSERT_ERROR(json:decode(<<"\"", 0, "\"">>)),
    ?ASSERT_ERROR(json:decode(<<"\"hello\nworld\"">>)),

    ?ASSERT_ERROR(json:decode(<<"\"\\uD800\"">>)),
    ?ASSERT_ERROR(json:decode(<<"\"\\uDC00\"">>)),
    ?ASSERT_ERROR(json:decode(<<"\"\\uD800\\u0041\"">>)),

    ?ASSERT_ERROR(json:decode(<<"-">>)),
    ?ASSERT_ERROR(json:decode(<<"1.">>)),
    ?ASSERT_ERROR(json:decode(<<"1e">>)),
    ?ASSERT_ERROR(json:decode(<<"1e+">>)),
    ok.

test_decode3() ->
    {42, my_acc, <<>>} = json:decode(<<"42">>, my_acc, #{}),
    {42, my_acc, <<"rest">>} = json:decode(<<"42rest">>, my_acc, #{}),

    {nil, ok, <<>>} = json:decode(<<"null">>, ok, #{null => nil}),

    StringFun = fun(Bin) -> binary_to_atom(Bin, utf8) end,
    {hello, ok, <<>>} = json:decode(<<"\"hello\"">>, ok, #{string => StringFun}),

    IntFun = fun(Bin) -> binary_to_integer(Bin) * 2 end,
    {84, ok, <<>>} = json:decode(<<"42">>, ok, #{integer => IntFun}),

    FloatFun = fun(Bin) -> round(binary_to_float(Bin)) end,
    {3, ok, <<>>} = json:decode(<<"3.14">>, ok, #{float => FloatFun}),

    ArrayDecoders = #{
        array_start => fun(_) -> {[], 0} end,
        array_push => fun(V, {Acc, Idx}) -> {[{Idx, V} | Acc], Idx + 1} end,
        array_finish => fun({Acc, _Idx}, OldAcc) -> {lists:reverse(Acc), OldAcc} end
    },
    {[{0, 1}, {1, 2}, {2, 3}], ok, <<>>} = json:decode(<<"[1,2,3]">>, ok, ArrayDecoders),

    ObjDecoders = #{
        object_start => fun(_) -> [] end,
        object_push => fun(K, V, Acc) -> [{K, V} | Acc] end,
        object_finish => fun(Acc, OldAcc) -> {lists:reverse(Acc), OldAcc} end
    },
    {[{<<"a">>, 1}, {<<"b">>, 2}], ok, <<>>} =
        json:decode(<<"{\"a\":1,\"b\":2}">>, ok, ObjDecoders),

    {42, ok, <<>>} = json:decode(<<"42 ">>, ok, #{}),
    {42, ok, <<" x">>} = json:decode(<<"42 x">>, ok, #{}),
    {true, ok, <<>>} = json:decode(<<"true  ">>, ok, #{}),
    {true, ok, <<"  x">>} = json:decode(<<"true  x">>, ok, #{}),
    ok.

test_decode_streaming() ->
    {true, ok, <<>>} = json:decode_start(<<"true">>, ok, #{}),

    {continue, S0} = json:decode_start(<<"42">>, ok, #{}),
    {42, ok, <<>>} = json:decode_continue(end_of_input, S0),

    {continue, S1} = json:decode_start(<<"[1,2">>, ok, #{}),
    {[1, 2, 3], ok, <<>>} = json:decode_continue(<<",3]">>, S1),

    {continue, S2} = json:decode_start(<<"\"hel">>, ok, #{}),
    {<<"hello">>, ok, <<>>} = json:decode_continue(<<"lo\"">>, S2),

    {continue, S3} = json:decode_start(<<"{">>, ok, #{}),
    {continue, S4} = json:decode_continue(<<"\"a\"">>, S3),
    {continue, S5} = json:decode_continue(<<":">>, S4),
    {continue, S6} = json:decode_continue(<<"1">>, S5),
    ?ASSERT_MATCH(#{<<"a">> => 1}, element(1, json:decode_continue(<<"}">>, S6))),

    {continue, S7} = json:decode_start(<<"[1,">>, ok, #{}),
    ?ASSERT_ERROR(json:decode_continue(end_of_input, S7)),

    {continue, S8} = json:decode_start(<<>>, ok, #{}),
    {continue, S9} = json:decode_continue(<<"42">>, S8),
    {42, ok, <<>>} = json:decode_continue(end_of_input, S9),

    {continue, S10} = json:decode_start(<<>>, ok, #{}),
    {42, ok, <<" x">>} = json:decode_continue(<<"42 x">>, S10),
    {continue, S11} = json:decode_start(<<>>, ok, #{}),
    {42, ok, <<>>} = json:decode_continue(<<"42 ">>, S11),

    ?ASSERT_ERROR(json:decode_start(<<"x">>, ok, #{})),
    ok.

test_decode_weather() ->
    Json =
        <<
            "{"
            "\"location\": {"
            "\"name\": \"\xe9\x82\xa3\xe9\xa0\x88\\u753A\","
            "\"country\": \"JP\","
            "\"coordinates\": [140.1209, 37.0198],"
            "\"utc_offset\": 9"
            "},"
            "\"current\": {"
            "\"temperature\": 18.5,"
            "\"humidity\": 62,"
            "\"conditions\": [\"partly_cloudy\", \"windy\"],"
            "\"wind\": {\"speed\": 5.2, \"direction\": \"NNW\"},"
            "\"precipitation\": false"
            "},"
            "\"forecast\": ["
            "{\"day\": 1, \"high\": 22.0, \"low\": 12.5, \"rain_probability\": 0.15},"
            "{\"day\": 2, \"high\": 19.0, \"low\": 10.0, \"rain_probability\": 0.80}"
            "],"
            "\"alerts\": null"
            "}"
        >>,
    Result = json:decode(Json),

    Location = maps:get(<<"location">>, Result),
    <<16#E9, 16#82, 16#A3, 16#E9, 16#A0, 16#88, 16#E7, 16#94, 16#BA>> = maps:get(
        <<"name">>, Location
    ),
    <<"JP">> = maps:get(<<"country">>, Location),
    [140.1209, 37.0198] = maps:get(<<"coordinates">>, Location),
    9 = maps:get(<<"utc_offset">>, Location),

    Current = maps:get(<<"current">>, Result),
    ?ASSERT_EQUALS(18.5, maps:get(<<"temperature">>, Current)),
    62 = maps:get(<<"humidity">>, Current),
    [<<"partly_cloudy">>, <<"windy">>] = maps:get(<<"conditions">>, Current),
    ?ASSERT_MATCH(
        #{<<"speed">> => 5.2, <<"direction">> => <<"NNW">>},
        maps:get(<<"wind">>, Current)
    ),
    false = maps:get(<<"precipitation">>, Current),

    [Day1, Day2] = maps:get(<<"forecast">>, Result),
    1 = maps:get(<<"day">>, Day1),
    ?ASSERT_EQUALS(22.0, maps:get(<<"high">>, Day1)),
    ?ASSERT_EQUALS(0.80, maps:get(<<"rain_probability">>, Day2)),

    null = maps:get(<<"alerts">>, Result),
    ok.

test_decode_edge_cases() ->
    0 = json:decode(<<"0">>),
    ?ASSERT_EQUALS(0.5, json:decode(<<"0.5">>)),
    ?ASSERT_ERROR(json:decode(<<"01">>)),
    {0, ok, <<"1">>} = json:decode(<<"01">>, ok, #{}),

    9007199254740993 = json:decode(<<"9007199254740993">>),

    ?ASSERT_EQUALS(1.0, json:decode(<<"1.0e0">>)),
    ?ASSERT_EQUALS(1.0, json:decode(<<"1.0e+0">>)),
    ?ASSERT_EQUALS(1.0, json:decode(<<"1.0e-0">>)),
    ok.

test_encode_basic() ->
    <<"0">> = to_bin(json:encode(0)),
    <<"42">> = to_bin(json:encode(42)),
    <<"-1">> = to_bin(json:encode(-1)),
    <<"9007199254740993">> = to_bin(json:encode(9007199254740993)),

    <<"1.0">> = to_bin(json:encode(1.0)),
    <<"3.14">> = to_bin(json:encode(3.14)),
    <<"-2.5">> = to_bin(json:encode(-2.5)),
    <<"-0.0">> = to_bin(json:encode(-0.0)),

    <<"true">> = to_bin(json:encode(true)),
    <<"false">> = to_bin(json:encode(false)),
    <<"null">> = to_bin(json:encode(null)),

    <<"\"hello\"">> = to_bin(json:encode(hello)),
    ok.

test_encode_strings() ->
    <<"\"\"">> = to_bin(json:encode(<<>>)),
    <<"\"hello\"">> = to_bin(json:encode(<<"hello">>)),
    <<"\"hello world\"">> = to_bin(json:encode(<<"hello world">>)),

    <<"\"\\\\\"">> = to_bin(json:encode(<<"\\">>)),
    <<"\"\\\"\"">> = to_bin(json:encode(<<"\"">>)),
    <<"\"\\n\"">> = to_bin(json:encode(<<"\n">>)),
    <<"\"\\r\"">> = to_bin(json:encode(<<"\r">>)),
    <<"\"\\t\"">> = to_bin(json:encode(<<"\t">>)),
    <<"\"\\b\"">> = to_bin(json:encode(<<"\b">>)),
    <<"\"\\f\"">> = to_bin(json:encode(<<"\f">>)),
    <<"\"\\u0001\"">> = to_bin(json:encode(<<1>>)),

    <<"\"hello\\nworld\"">> = to_bin(json:encode(<<"hello\nworld">>)),

    Bin = <<16#C3, 16#A9>>,
    <<"\"", 16#C3, 16#A9, "\"">> = to_bin(json:encode(Bin)),

    <<"\"hello\"">> = to_bin(json:encode_binary_escape_all(<<"hello">>)),
    <<"\"\\u00E9\"">> = to_bin(json:encode_binary_escape_all(<<16#C3, 16#A9>>)),
    <<"\"\\uD83D\\uDE00\"">> = to_bin(
        json:encode_binary_escape_all(<<16#F0, 16#9F, 16#98, 16#80>>)
    ),

    ?ASSERT_ERROR(json:encode(<<16#FF>>)),
    ?ASSERT_ERROR(json:encode(<<16#80>>)),
    ok.

test_encode_arrays() ->
    <<"[]">> = to_bin(json:encode([])),
    <<"[1]">> = to_bin(json:encode([1])),
    <<"[1,2,3]">> = to_bin(json:encode([1, 2, 3])),
    <<"[1,\"two\",true,null]">> = to_bin(json:encode([1, <<"two">>, true, null])),
    <<"[[1,2],[3,4]]">> = to_bin(json:encode([[1, 2], [3, 4]])),

    ?ASSERT_EQUALS(
        <<"{\"hello\":[119,111,114,108,100]}">>,
        to_bin(json:encode(#{hello => "world"}))
    ),
    ok.

test_encode_objects() ->
    <<"{}">> = to_bin(json:encode(#{})),

    ?ASSERT_MATCH(
        #{<<"a">> => 1, <<"b">> => 2},
        json:decode(to_bin(json:encode(#{<<"a">> => 1, <<"b">> => 2})))
    ),

    AtomResult = json:decode(to_bin(json:encode(#{foo => 1, bar => 2}))),
    1 = maps:get(<<"foo">>, AtomResult),
    2 = maps:get(<<"bar">>, AtomResult),

    ?ASSERT_EQUALS(
        to_bin(json:encode(#{<<"hello">> => <<"world">>})),
        to_bin(json:encode(#{hello => <<"world">>}))
    ),

    IntResult = json:decode(to_bin(json:encode(#{1 => <<"one">>, 2 => <<"two">>}))),
    <<"one">> = maps:get(<<"1">>, IntResult),
    <<"two">> = maps:get(<<"2">>, IntResult),

    Nested = #{<<"a">> => #{<<"b">> => 1}},
    ?ASSERT_MATCH(Nested, json:decode(to_bin(json:encode(Nested)))),
    ok.

test_encode_key_value_list() ->
    ?ASSERT_EQUALS(
        <<"{\"a\":1,\"b\":2}">>,
        to_bin(json:encode_key_value_list([{<<"a">>, 1}, {<<"b">>, 2}], fun json:encode_value/2))
    ),
    ok.

test_encode_checked() ->
    ?ASSERT_ERROR(
        json:encode_key_value_list_checked(
            [{<<"a">>, 1}, {<<"a">>, 2}], fun json:encode_value/2
        )
    ),

    ?ASSERT_ERROR(
        json:encode_map_checked(#{foo => 1, <<"foo">> => 2}, fun json:encode_value/2)
    ),
    ok.

test_encode_errors() ->
    ?ASSERT_ERROR(json:encode({a, tuple})),
    ?ASSERT_ERROR(json:encode([{hello, <<"world">>}])),
    ?ASSERT_ERROR(json:encode(#{"hello" => <<"world">>})),
    ok.

test_roundtrip() ->
    Terms = [
        42,
        -1,
        0,
        3.14,
        -0.0,
        true,
        false,
        null,
        <<"hello">>,
        <<>>,
        [],
        [1, 2, 3],
        #{},
        #{<<"key">> => <<"value">>},
        [#{<<"a">> => [1, true, null]}]
    ],
    lists:foreach(
        fun(Term) ->
            ?ASSERT_EQUALS(Term, json:decode(to_bin(json:encode(Term))))
        end,
        Terms
    ),
    ok.

test_streaming_splits() ->
    {continue, S5} = json:decode_start(<<"tr">>, ok, #{}),
    {true, ok, <<>>} = json:decode_continue(<<"ue">>, S5),

    {continue, S6} = json:decode_start(<<"nu">>, ok, #{}),
    {null, ok, <<>>} = json:decode_continue(<<"ll">>, S6),

    {continue, S7} = json:decode_start(<<"\"hel">>, ok, #{}),
    {<<"hello">>, ok, <<>>} = json:decode_continue(<<"lo\"">>, S7),

    {continue, S8} = json:decode_start(<<"\"\\u00">>, ok, #{}),
    {<<"A">>, ok, <<>>} = json:decode_continue(<<"41\"">>, S8),

    {continue, S9} = json:decode_start(<<"[1,">>, ok, #{}),
    {[1, 2], ok, <<>>} = json:decode_continue(<<"2]">>, S9),

    {continue, S10} = json:decode_start(<<"-">>, ok, #{}),
    {-42, ok, <<>>} = json:decode_continue(<<"42 ">>, S10),

    {continue, S3} = json:decode_start(<<"3.">>, ok, #{}),
    {3.14, ok, <<>>} = json:decode_continue(<<"14 ">>, S3),

    {continue, S4} = json:decode_start(<<"1e">>, ok, #{}),
    {1.0e5, ok, <<>>} = json:decode_continue(<<"5 ">>, S4),

    {continue, S11} = json:decode_start(<<"1.5e">>, ok, #{}),
    {1.5e3, ok, <<>>} = json:decode_continue(<<"3 ">>, S11),
    ok.

test_streaming_end_of_input() ->
    {continue, S1} = json:decode_start(<<"[1,">>, ok, #{}),
    ok =
        try json:decode_continue(end_of_input, S1) of
            _ -> error(should_have_failed)
        catch
            error:unexpected_end -> ok
        end,

    {continue, S2} = json:decode_start(<<>>, ok, #{}),
    ok =
        try json:decode_continue(end_of_input, S2) of
            _ -> error(should_have_failed)
        catch
            error:unexpected_end -> ok
        end,

    {continue, S3} = json:decode_start(<<"\"abc">>, ok, #{}),
    ok =
        try json:decode_continue(end_of_input, S3) of
            _ -> error(should_have_failed)
        catch
            error:unexpected_end -> ok
        end,

    {continue, S4} = json:decode_start(<<"tru">>, ok, #{}),
    ok =
        try json:decode_continue(end_of_input, S4) of
            _ -> error(should_have_failed)
        catch
            error:unexpected_end -> ok
        end,
    ok.

test_streaming_number_boundary() ->
    {continue, S1} = json:decode_start(<<"42">>, ok, #{}),
    {continue, S2} = json:decode_continue(<<"3">>, S1),
    {423, ok, <<>>} = json:decode_continue(end_of_input, S2),

    {continue, S3} = json:decode_start(<<"1">>, ok, #{}),
    {12, ok, <<>>} = json:decode_continue(<<"2 ">>, S3),

    {continue, S4} = json:decode_start(<<"0">>, ok, #{}),
    {0, ok, <<>>} = json:decode_continue(end_of_input, S4),

    {continue, S5} = json:decode_start(<<"3.14">>, ok, #{}),
    {3.14, ok, <<>>} = json:decode_continue(end_of_input, S5),

    {continue, S6} = json:decode_start(<<"1e5">>, ok, #{}),
    {1.0e5, ok, <<>>} = json:decode_continue(end_of_input, S6),

    {continue, S7} = json:decode_start(<<"-42">>, ok, #{}),
    {-42, ok, <<>>} = json:decode_continue(end_of_input, S7),

    42 = json:decode(<<"42">>),
    0 = json:decode(<<"0">>),
    3.14 = json:decode(<<"3.14">>),
    1.0e5 = json:decode(<<"1e5">>),
    -1 = json:decode(<<"-1">>),
    ok.

test_hex_error_classification() ->
    ok =
        try json:decode(<<"\"\\uGGGG\"">>) of
            _ -> error(should_have_failed)
        catch
            error:{unexpected_sequence, _} -> ok;
            error:{invalid_byte, _} -> error(wrong_error_tag)
        end,

    ok =
        try json:decode(<<"\"\\uD83D\\uZZZZ\"">>) of
            _ -> error(should_have_failed)
        catch
            error:{unexpected_sequence, _} -> ok;
            error:{invalid_byte, _} -> error(wrong_error_tag)
        end,
    ok.

test_encode_custom_key_encoder() ->
    Enc = fun
        (B, _E) when is_binary(B) -> json:encode_binary_escape_all(B);
        (Other, E) -> json:encode_value(Other, E)
    end,
    Result = iolist_to_binary(json:encode_map(#{<<16#C3, 16#A9>> => <<"v">>}, Enc)),
    Expected = <<"{\"\\u00E9\":\"v\"}">>,
    ?ASSERT_EQUALS(Expected, Result),
    ok.

test_encode_checked_custom_key_encoder() ->
    Enc = fun
        (B, _E) when is_binary(B) -> json:encode_binary_escape_all(B);
        (Other, E) -> json:encode_value(Other, E)
    end,
    Result = iolist_to_binary(
        json:encode_map_checked(#{<<16#C3, 16#A9>> => <<"v">>}, Enc)
    ),
    Expected = <<"{\"\\u00E9\":\"v\"}">>,
    ?ASSERT_EQUALS(Expected, Result),
    ok.

test_streaming_sliding_split() ->
    Jsons = sliding_split_jsons(),
    lists:foreach(fun run_sliding_split/1, Jsons),
    ok.

run_sliding_split(Json) ->
    Expected = json:decode(Json),
    Size = byte_size(Json),
    lists:foreach(
        fun(Pos) ->
            Left = binary_part(Json, 0, Pos),
            Right = binary_part(Json, Pos, Size - Pos),
            Result = streaming_decode(Left, Right),
            case Result of
                Expected ->
                    ok;
                Other ->
                    error(
                        {sliding_split_mismatch, [
                            {json, Json},
                            {split_at, Pos},
                            {expected, Expected},
                            {got, Other}
                        ]}
                    )
            end
        end,
        lists:seq(0, Size)
    ).

streaming_decode(Left, Right) ->
    case json:decode_start(Left, ok, #{}) of
        {Value, ok, Rest} ->
            %% Value complete in first chunk — remaining must be whitespace only
            case skip_ws(<<Rest/binary, Right/binary>>) of
                <<>> -> Value;
                _ -> error({unexpected_trailing, Left, Right, Value, Rest})
            end;
        {continue, State} ->
            streaming_continue(Right, State)
    end.

streaming_continue(<<>>, State) ->
    {Value, ok, <<>>} = json:decode_continue(end_of_input, State),
    Value;
streaming_continue(Data, State) ->
    case json:decode_continue(Data, State) of
        {Value, ok, _Rest} ->
            Value;
        {continue, State2} ->
            {Value, ok, <<>>} =
                json:decode_continue(end_of_input, State2),
            Value
    end.

skip_ws(<<$\s, R/binary>>) -> skip_ws(R);
skip_ws(<<$\t, R/binary>>) -> skip_ws(R);
skip_ws(<<$\n, R/binary>>) -> skip_ws(R);
skip_ws(<<$\r, R/binary>>) -> skip_ws(R);
skip_ws(Bin) -> Bin.

test_streaming_byte_by_byte() ->
    lists:foreach(fun run_byte_by_byte/1, sliding_split_jsons()),
    ok.

run_byte_by_byte(Json) ->
    Expected = json:decode(Json),
    <<First, Rest/binary>> = Json,
    {continue, State} = json:decode_start(<<First>>, ok, #{}),
    Result = feed_bytes(Rest, State),
    case Result of
        Expected -> ok;
        Other -> error({byte_by_byte_mismatch, [{json, Json}, {expected, Expected}, {got, Other}]})
    end.

feed_bytes(<<>>, State) ->
    {Value, ok, <<>>} = json:decode_continue(end_of_input, State),
    Value;
feed_bytes(<<B, Rest/binary>>, State) ->
    case json:decode_continue(<<B>>, State) of
        {Value, ok, _} when Rest =:= <<>> -> Value;
        {continue, State2} -> feed_bytes(Rest, State2)
    end.

sliding_split_jsons() ->
    [
        %% Mixed types with null
        <<"{\"temp\":18.5,\"wind\":null,\"rain\":false}">>,
        %% Array of mixed types
        <<"[1,-42,3.14,true,false,null,\"hello\"]">>,
        %% Nested objects
        <<"{\"a\":{\"b\":{\"c\":[1,2,3]}}}">>,
        %% Unicode escapes
        <<
            "{\"key\":\"caf\\u00E9\","
            "\"emoji\":\"\\uD83D\\uDE00\"}"
        >>,
        %% Kanji via unicode escapes
        <<
            "{\"name\":\"\\u90A3\\u9808\\u753A\","
            "\"country\":\"JP\"}"
        >>,
        %% Array of objects
        <<
            "[{\"id\":1,\"v\":true},"
            "{\"id\":2,\"v\":false}]"
        >>,
        %% Floats and exponents
        <<"{\"data\":[1.0e5,-0.0,1.5e-3],\"ok\":true}">>,
        %% String escapes
        <<
            "{\"path\":\"C:\\\\dir\\\\file\","
            "\"msg\":\"say \\\"hi\\\"\\n\"}"
        >>,
        %% Large integer + empty containers
        <<
            "{\"big\":9007199254740993,"
            "\"a\":[],\"o\":{}}"
        >>,
        %% Complex nested
        <<
            "[{\"k\":[null,[true,{\"x\":-1}]],"
            "\"y\":\"z\"}]"
        >>,
        %% Long UTF-8 (U+FBFD, 3-byte)
        <<
            "{\"longutf8\":\"\xEF\xAF\xB9\","
            "\"codepoint\":64505}"
        >>,
        %% Repeated long UTF-8
        <<
            "{\"longutf8repeated\":"
            "\"\xEF\xAF\xB9\xEF\xAF\xB9\xEF\xAF\xB9"
            "\xEF\xAF\xB9\xEF\xAF\xB9\","
            "\"is_repeated\":true}"
        >>,

        <<"42">>,
        <<"-1">>,
        <<"0">>,
        <<"3.14">>,
        <<"-0.5">>,
        <<"1e5">>,
        <<"1.5e-3">>,
        <<"-2.5e10">>,
        <<"true">>,
        <<"false">>,
        <<"null">>,
        <<"\"hello\"">>,
        <<"\"\"">>,
        <<"\"caf\\u00E9\"">>,
        <<"\"\\uD83D\\uDE00\"">>,
        <<"\"", 230, 188, 162, 229, 173, 151, "\"">>,
        <<"\"\\uD83D\\uDE00", 231, 181, 181, 230, 150, 135, 229, 173, 151, "\"">>,
        <<"\"nottrue\"">>,
        <<"\"notfalse\"">>,
        <<"\"notnull\"">>,
        <<"\"not42\"">>,
        <<"\"true-as-suffix\"">>,
        <<"\"false-as-suffix\"">>,
        <<"\"null-as-suffix\"">>,
        <<"\"true\"">>,
        <<"\"false\"">>,
        <<"\"null\"">>,

        <<
            "{\"location\":{\"name\":\"\\u90A3\\u9808\\u753A\","
            "\"country\":\"JP\","
            "\"coordinates\":[140.1209,37.0198],"
            "\"utc_offset\":9},"
            "\"current\":{\"temperature\":18.5,"
            "\"humidity\":62,"
            "\"conditions\":[\"partly_cloudy\",\"windy\"],"
            "\"wind\":{\"speed\":5.2,\"direction\":\"NNW\"},"
            "\"precipitation\":false},"
            "\"forecast\":["
            "{\"day\":1,\"high\":22.0,\"low\":12.5,"
            "\"rain_probability\":0.15},"
            "{\"day\":2,\"high\":19.0,\"low\":10.0,"
            "\"rain_probability\":0.80}],"
            "\"alerts\":null}"
        >>
    ].

test_deep_nesting() ->
    %% 1000 nested arrays: [[[...[1]...]]]
    N = 1000,
    Open = binary:copy(<<"[">>, N),
    Close = binary:copy(<<"]">>, N),
    Bin = <<Open/binary, "1", Close/binary>>,
    Expected = nest_value(1, N),
    Expected = json:decode(Bin),
    %% 1000 nested objects: {"k":{"k":...1...}}
    ObjOpen = iolist_to_binary(lists:duplicate(N, <<"{\"k\":">>)),
    ObjClose = binary:copy(<<"}">>, N),
    ObjBin = <<ObjOpen/binary, "1", ObjClose/binary>>,
    _ = json:decode(ObjBin),
    {continue, S1} = json:decode_start(Open, ok, #{}),
    {Expected, ok, <<>>} = json:decode_continue(<<"1", Close/binary>>, S1),
    ok =
        try json:decode(Open) of
            _ -> error(should_have_failed)
        catch
            error:unexpected_end -> ok
        end,
    %% Equivalent to the JSONTestSuite files that were excluded:
    %%   n_structure_100000_opening_arrays.json (100000 x "[")
    %%   n_structure_open_array_object.json (50000 x "[{"":")
    %% Full-size (100K) would pass but takes too long due to AtomVM GC pressure
    %% on the growing stack list. 10K proves the iterative decoder handles
    %% arbitrary depth without call-stack overflow.
    ok = expect_error(binary:copy(<<"[">>, 10000)),
    ok = expect_error(binary:copy(<<"[{\"\":">>, 5000)),
    ok.

expect_error(Bin) ->
    try json:decode(Bin) of
        _ -> error(should_have_failed)
    catch
        error:_ -> ok
    end.

nest_value(Value, 0) -> Value;
nest_value(Value, N) -> nest_value([Value], N - 1).

