test_encode_truncated_utf8() ->
    %% Valid truncated UTF-8 sequences must raise unexpected_end (not invalid_byte)
    %% 2-byte lead, no continuation (e.g. start of é = C3 A9)
    ok =
        try json:encode_binary(<<16#C3>>) of
            _ -> error(should_have_failed)
        catch
            error:unexpected_end -> ok
        end,
    %% 3-byte lead alone (e.g. start of – = E2 80 93)
    ok =
        try json:encode_binary(<<16#E2>>) of
            _ -> error(should_have_failed)
        catch
            error:unexpected_end -> ok
        end,
    %% 3-byte lead + 1 continuation (valid prefix)
    ok =
        try json:encode_binary(<<16#E2, 16#80>>) of
            _ -> error(should_have_failed)
        catch
            error:unexpected_end -> ok
        end,
    %% 4-byte lead alone (e.g. start of U+1F600)
    ok =
        try json:encode_binary(<<16#F0>>) of
            _ -> error(should_have_failed)
        catch
            error:unexpected_end -> ok
        end,
    %% 4-byte lead + 1 continuation
    ok =
        try json:encode_binary(<<16#F0, 16#9F>>) of
            _ -> error(should_have_failed)
        catch
            error:unexpected_end -> ok
        end,
    %% 4-byte lead + 2 continuations
    ok =
        try json:encode_binary(<<16#F0, 16#9F, 16#98>>) of
            _ -> error(should_have_failed)
        catch
            error:unexpected_end -> ok
        end,
    %% Truly invalid bytes must still raise {invalid_byte, _}
    ok =
        try json:encode_binary(<<16#FF>>) of
            _ -> error(should_have_failed)
        catch
            error:{invalid_byte, 16#FF} -> ok
        end,
    ok =
        try json:encode_binary(<<16#80>>) of
            _ -> error(should_have_failed)
        catch
            error:{invalid_byte, 16#80} -> ok
        end,
    ok.

test_encode_checked_normalizing_encoder() ->
    %% Custom encoder that uppercases keys — duplicate detection must use
    %% encoded (post-normalization) keys, not raw keys.
    Enc = fun
        (B, _E) when is_binary(B) ->
            json:encode_binary(string:uppercase(B));
        (Other, E) ->
            json:encode_value(Other, E)
    end,
    ?ASSERT_ERROR(
        json:encode_map_checked(#{<<"foo">> => 1, <<"FOO">> => 2}, Enc)
    ),
    ?ASSERT_ERROR(
        json:encode_key_value_list_checked(
            [{<<"foo">>, 1}, {<<"FOO">>, 2}], Enc
        )
    ),
    ok.

test_encode_weather() ->
    NasuMachi = <<16#E9, 16#82, 16#A3, 16#E9, 16#A0, 16#88, 16#E7, 16#94, 16#BA>>,
    Weather = #{
        <<"location">> => #{
            <<"name">> => NasuMachi,
            <<"country">> => <<"JP">>,
            <<"coordinates">> => [140.1209, 37.0198],
            <<"utc_offset">> => 9
        },
        <<"current">> => #{
            <<"temperature">> => 18.5,
            <<"humidity">> => 62,
            <<"conditions">> => [<<"partly_cloudy">>, <<"windy">>],
            <<"wind">> => #{<<"speed">> => 5.2, <<"direction">> => <<"NNW">>},
            <<"precipitation">> => false
        },
        <<"forecast">> => [
            #{
                <<"day">> => 1,
                <<"high">> => 22.0,
                <<"low">> => 12.5,
                <<"rain_probability">> => 0.15
            },
            #{<<"day">> => 2, <<"high">> => 19.0, <<"low">> => 10.0, <<"rain_probability">> => 0.80}
        ],
        <<"alerts">> => null
    },
    Encoded = to_bin(json:encode(Weather)),
    Decoded = json:decode(Encoded),

    Location = maps:get(<<"location">>, Decoded),
    NasuMachi = maps:get(<<"name">>, Location),
    <<"JP">> = maps:get(<<"country">>, Location),
    [140.1209, 37.0198] = maps:get(<<"coordinates">>, Location),
    9 = maps:get(<<"utc_offset">>, Location),

    Current = maps:get(<<"current">>, Decoded),
    ?ASSERT_EQUALS(18.5, maps:get(<<"temperature">>, Current)),
    62 = maps:get(<<"humidity">>, Current),
    [<<"partly_cloudy">>, <<"windy">>] = maps:get(<<"conditions">>, Current),
    ?ASSERT_EQUALS(5.2, maps:get(<<"speed">>, maps:get(<<"wind">>, Current))),
    <<"NNW">> = maps:get(<<"direction">>, maps:get(<<"wind">>, Current)),
    false = maps:get(<<"precipitation">>, Current),

    [Day1, Day2] = maps:get(<<"forecast">>, Decoded),
    1 = maps:get(<<"day">>, Day1),
    ?ASSERT_EQUALS(22.0, maps:get(<<"high">>, Day1)),
    ?ASSERT_EQUALS(12.5, maps:get(<<"low">>, Day1)),
    ?ASSERT_EQUALS(0.15, maps:get(<<"rain_probability">>, Day1)),
    2 = maps:get(<<"day">>, Day2),
    ?ASSERT_EQUALS(0.80, maps:get(<<"rain_probability">>, Day2)),

    null = maps:get(<<"alerts">>, Decoded),
    ok.
